        status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
        detail={"ok": False, "code": "validation_failed", "errors": errors},
    )


@app.exception_handler(HTTPException)
async def http_exception_handler(_: Request, exc: HTTPException):
    if isinstance(exc.detail, dict):
        return JSONResponse(status_code=exc.status_code, content=exc.detail)
    return JSONResponse(
        status_code=exc.status_code,
        content={"ok": False, "code": "error", "message": str(exc.detail)},
    )


@app.middleware("http")
async def security_headers_and_body_limit(request: Request, call_next):
    body_len = request.headers.get("content-length")
    if body_len and int(body_len) > MAX_BODY_BYTES:
        return JSONResponse(
            status_code=413,
            content={"ok": False, "code": "body_too_large"},
        )

    response = await call_next(request)
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["X-Frame-Options"] = "DENY"
    response.headers["Referrer-Policy"] = "no-referrer"
    response.headers["Cache-Control"] = "no-store"
    return response


def client_ip(request: Request) -> str:
    # Do not trust X-Forwarded-For unless your reverse proxy strips spoofed headers.
    return request.client.host if request.client else "unknown"


def normalize_text(value: str) -> str:
    value = unicodedata.normalize("NFKC", value)
    value = value.replace("\r", "").replace("\n", "")
    return value.strip()


def contains_control_or_invisible(value: str) -> bool:
    return bool(CONTROL_OR_INVISIBLE_RE.search(value))


def has_mixed_scripts(value: str) -> bool:
    scripts = set()
    for ch in value:
        if ch.isascii() or ch.isdigit() or ch in " ._-'":
            continue
        name = unicodedata.name(ch, "")
        for script in ("LATIN", "CYRILLIC", "GREEK", "HEBREW", "ARABIC", "CJK"):
            if script in name:
                scripts.add(script)
    return len(scripts) > 1


def offensive(value: str) -> bool:
    compact = value.casefold()
    compact = compact.translate(str.maketrans({"0": "o", "1": "i", "3": "e", "4": "a", "5": "s", "7": "t", "@": "a", "$": "s"}))
    return any(bad in compact for bad in OFFENSIVE_SUBSTRINGS)


def validate_and_normalize_email(raw: Any) -> tuple[str | None, str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, None, [error("email", "type", "Email must be a string.")]

    original = raw
    email_value = normalize_text(raw)

    if email_value != original.strip():
        errors.append(error("email", "normalized", "Email contains unsupported whitespace or unicode forms."))

    if not email_value:
        errors.append(error("email", "required", "Email is required."))

    if len(email_value) > 254 or len(email_value.encode("utf-8")) > 320:
        errors.append(error("email", "too_long", "Email is too long."))

    if contains_control_or_invisible(email_value):
        errors.append(error("email", "invisible_chars", "Email contains control or invisible characters."))

    if email_value.count("@") != 1:
        errors.append(error("email", "format", "Email must contain exactly one @ sign."))

    normalized_email = None
    domain = None

    if not errors:
        try:
            info = validate_email(
                email_value,
                allow_smtputf8=False,
                allow_quoted_local=False,
                check_deliverability=False,
            )
            normalized_email = info.normalized.casefold()
            domain = info.domain.casefold()
        except EmailNotValidError:
            errors.append(error("email", "format", "Enter a valid email address."))

    if normalized_email and domain:
        local = normalized_email.split("@", 1)[0]

        if len(local) > 64:
            errors.append(error("email", "local_too_long", "Email local part is too long."))

        if ".." in local or ".." in domain:
            errors.append(error("email", "dots", "Email contains consecutive dots."))

        if domain in BLOCKED_EMAIL_DOMAINS or any(domain.endswith("." + d) for d in BLOCKED_EMAIL_DOMAINS):
            errors.append(error("email", "blocked_domain", "Email domain is not allowed."))

        if domain in DISPOSABLE_DOMAINS or any(domain.endswith("." + d) for d in DISPOSABLE_DOMAINS):
            errors.append(error("email", "disposable", "Disposable email addresses are not allowed."))

        try:
            ipaddress.ip_address(domain.strip("[]"))
            errors.append(error("email", "ip_literal", "Email domain cannot be an IP address."))
        except ValueError:
            pass

        if "." not in domain:
            errors.append(error("email", "domain", "Email domain must be fully qualified."))

        if domain.endswith(".test") or domain.endswith(".invalid") or domain.endswith(".localhost"):
            errors.append(error("email", "reserved_tld", "Email domain uses a reserved TLD."))

        try:
            mx_records = dns.resolver.resolve(domain, "MX", lifetime=2.0)
            if not mx_records:
                errors.append(error("email", "mx", "Email domain does not accept mail."))
        except Exception:
            # Avoid hard-failing signups because of transient DNS issues.
            # In production, queue a verification email and reject if delivery fails.
            pass

    return normalized_email, domain, errors


def validate_and_normalize_username(raw: Any) -> tuple[str | None, str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, None, [error("username", "type", "Username must be a string.")]

    username = normalize_text(raw)
    username_norm = username.casefold()

    if not username:
        errors.append(error("username", "required", "Username is required."))

    if len(username) < 3:
        errors.append(error("username", "too_short", "Username must be at least 3 characters."))

    if len(username) > 32:
        errors.append(error("username", "too_long", "Username must be at most 32 characters."))

    if len(username.encode("utf-8")) > 64:
        errors.append(error("username", "too_many_bytes", "Username is too large."))

    if contains_control_or_invisible(username):
        errors.append(error("username", "invisible_chars", "Username contains control or invisible characters."))

    if not username.isascii():
        errors.append(error("username", "ascii_only", "Username must use ASCII characters only."))

    if not USERNAME_RE.fullmatch(username):
        errors.append(
            error(
                "username",
                "characters",
                "Username must start with a letter and contain only letters, numbers, dot, underscore, or hyphen.",
            )
        )

    if username_norm in RESERVED_USERNAMES:
        errors.append(error("username", "reserved", "Username is reserved."))

    if username_norm.startswith(("admin", "root", "support", "security")):
        errors.append(error("username", "impersonation", "Username may not impersonate staff or system accounts."))

    if username_norm.endswith((".", "-", "_")):
        errors.append(error("username", "trailing_punctuation", "Username cannot end with punctuation."))

    if any(x in username_norm for x in ("..", "__", "--", ".-", "-.", "._", "_.")):
        errors.append(error("username", "repeated_punctuation", "Username contains unsafe punctuation patterns."))

    if "@" in username_norm or URLISH_RE.search(username_norm):
        errors.append(error("username", "url_or_email", "Username cannot look like an email address or URL."))

    if re.fullmatch(r"\d+", username_norm):
        errors.append(error("username", "numeric", "Username cannot be only numbers."))

    if offensive(username_norm):
        errors.append(error("username", "offensive", "Username is not allowed."))

    return username, username_norm, errors


def validate_and_sanitize_display_name(raw: Any) -> tuple[str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, [error("display_name", "type", "Display name must be a string.")]

    display = unicodedata.normalize("NFKC", raw)
    display = " ".join(display.split())
    display = bleach.clean(display, tags=[], attributes={}, strip=True)

    if not display:
        errors.append(error("display_name", "required", "Display name is required."))

    if len(display) > 80:
        errors.append(error("display_name", "too_long", "Display name must be at most 80 characters."))

    if len(display.encode("utf-8")) > 160:
        errors.append(error("display_name", "too_many_bytes", "Display name is too large."))

    if contains_control_or_invisible(display):
        errors.append(error("display_name", "invisible_chars", "Display name contains control or invisible characters."))

    if URLISH_RE.search(display):
        errors.append(error("display_name", "url", "Display name cannot contain URLs."))

    if has_mixed_scripts(display):
        errors.append(error("display_name", "mixed_scripts", "Display name mixes visually confusing scripts."))

    if offensive(display):
        errors.append(error("display_name", "offensive", "Display name is not allowed."))

    return display, errors


def password_has_sequence(password: str) -> bool:
    lower = password.casefold()
    sequences = [
        "0123456789", "9876543210",
        "abcdefghijklmnopqrstuvwxyz",
        "zyxwvutsrqponmlkjihgfedcba",
        "qwertyuiop", "poiuytrewq",
        "asdfghjkl", "lkjhgfdsa",
    ]
    return any(seq[i:i + 5] in lower for seq in sequences for i in range(len(seq) - 4))


async def breached_password_count(password: str) -> int | None:
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    try:
        async with httpx.AsyncClient(timeout=2.5) as client:
            response = await client.get(
                f"https://api.pwnedpasswords.com/range/{prefix}",
                headers={"Add-Padding": "true", "User-Agent": "registration-validator"},
            )
            response.raise_for_status()
    except Exception:
        return None

    for line in response.text.splitlines():
        candidate_suffix, count = line.split(":", 1)
        if hmac.compare_digest(candidate_suffix, suffix):
            return int(count)
    return 0


async def validate_password(raw: Any, email_norm: str | None, username_norm: str | None, display_name: str | None) -> tuple[str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, [error("password", "type", "Password must be a string.")]

    password = unicodedata.normalize("NFKC", raw)

    if not password:
        errors.append(error("password", "required", "Password is required."))

    if len(password) < 12:
        errors.append(error("password", "too_short", "Password must be at least 12 characters."))

    if len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        errors.append(error("password", "too_long", "Password is too long."))

    if contains_control_or_invisible(password) or any(ch in password for ch in "\r\n\t\x00"):
        errors.append(error("password", "control_chars", "Password cannot contain control characters."))

    if password.casefold() in COMMON_PASSWORDS:
        errors.append(error("password", "common", "Password is too common."))

    categories = {
        "lower": any(c.islower() for c in password),
        "upper": any(c.isupper() for c in password),
        "digit": any(c.isdigit() for c in password),
        "symbol": any(not c.isalnum() for c in password),
    }
    if sum(categories.values()) < 3:
        errors.append(error("password", "complexity", "Password must include at least three character classes."))

    if len(set(password.casefold())) < 6:
        errors.append(error("password", "variety", "Password must contain more unique characters."))

    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "repeated_chars", "Password contains too many repeated characters."))

    if password_has_sequence(password):
        errors.append(error("password", "sequence", "Password contains an obvious sequence."))

    comparison_tokens = set()
    if username_norm:
        comparison_tokens.add(username_norm)
    if email_norm:
        local, domain = email_norm.split("@", 1)
        comparison_tokens.update({local, domain.split(".", 1)[0]})
    if display_name:
        comparison_tokens.update(t.casefold() for t in re.findall(r"[a-zA-Z0-9]{3,}", display_name))

    folded_password = password.casefold()
    for token in comparison_tokens:
        if len(token) >= 3 and token in folded_password:
            errors.append(error("password", "personal_info", "Password cannot contain your email, username, or display name."))
            break
        if len(token) >= 5 and SequenceMatcher(None, folded_password, token).ratio() > 0.72:
            errors.append(error("password", "similarity", "Password is too similar to your account details."))
            break

    if not errors:
        breach_count = await breached_password_count(password)
        if breach_count and breach_count > 0:
            errors.append(error("password", "breached", "Password appears in known breach data."))

    return password, errors


async def csrf_protect(request: Request) -> None:
    origin = request.headers.get("origin")
    if origin and origin not in ALLOWED_ORIGINS:
        raise HTTPException(
            status_code=403,
            detail={"ok": False, "code": "bad_origin", "message": "Origin is not allowed."},
        )

    if not ENFORCE_CSRF:
        return

    cookie_token = request.cookies.get("csrf_token")
    header_token = request.headers.get("x-csrf-token")

    if not cookie_token or not header_token or not hmac.compare_digest(cookie_token, header_token):
        raise HTTPException(
            status_code=403,
            detail={"ok": False, "code": "csrf_failed", "message": "CSRF validation failed."},
        )


def rate_limit_or_429(key: str, limit: int, window_seconds: int) -> None:
    retry_after = rate_limiter.check(key, limit, window_seconds)
    if retry_after is not None:
        raise HTTPException(
            status_code=429,
            detail={
                "ok": False,
                "code": "rate_limited",
                "message": "Too many registration attempts.",
                "retry_after_seconds": retry_after,
            },
        )


async def parse_json_body(request: Request) -> dict[str, Any]:
    if "application/json" not in request.headers.get("content-type", ""):
        raise HTTPException(
            status_code=415,
            detail={"ok": False, "code": "unsupported_media_type", "message": "Use application/json."},
        )

    try:
        data = await request.json()
    except Exception:
        raise HTTPException(
            status_code=400,
            detail={"ok": False, "code": "invalid_json", "message": "Malformed JSON."},
        )

    if not isinstance(data, dict):
        raise HTTPException(
            status_code=400,
            detail={"ok": False, "code": "invalid_body", "message": "JSON body must be an object."},
        )

    return data


def verification_hash(token: str) -> str:
    return hmac.new(APP_SECRET.encode(), token.encode(), hashlib.sha256).hexdigest()


async def pad_response(start: float, minimum_seconds: float = 0.35) -> None:
    elapsed = time.monotonic() - start
    if elapsed < minimum_seconds:
        await asyncio.sleep(minimum_seconds - elapsed)


@app.post("/api/register", status_code=202)
async def register(request: Request, _: None = Depends(csrf_protect)):
    start = time.monotonic()

    ip = client_ip(request)
    rate_limit_or_429(f"register:ip:{ip}", limit=5, window_seconds=10 * 60)

    data = await parse_json_body(request)

    allowed_fields = {"email", "username", "password", "display_name"}
    errors: list[dict[str, str]] = []

    extra_fields = set(data) - allowed_fields
    for field in sorted(extra_fields):
        errors.append(error(field, "unknown_field", "Unknown field is not allowed."))

    missing_fields = allowed_fields - set(data)
    for field in sorted(missing_fields):
        errors.append(error(field, "required", f"{field} is required."))

    email_norm, email_domain, email_errors = validate_and_normalize_email(data.get("email"))
    username, username_norm, username_errors = validate_and_normalize_username(data.get("username"))
    display_name, display_errors = validate_and_sanitize_display_name(data.get("display_name"))

    errors.extend(email_errors)
    errors.extend(username_errors)
    errors.extend(display_errors)

    password, password_errors = await validate_password(
        data.get("password"),
        email_norm=email_norm,
        username_norm=username_norm,
        display_name=display_name,
    )
    errors.extend(password_errors)

    if email_norm:
        email_rate_key = hmac.new(APP_SECRET.encode(), email_norm.encode(), hashlib.sha256).hexdigest()
        rate_limit_or_429(f"register:email:{email_rate_key}", limit=3, window_seconds=60 * 60)

    if errors:
        reject_validation(errors)

    now = datetime.now(timezone.utc)

    with SessionLocal() as db:
        # Parameterized query via SQLAlchemy Core.
        username_exists = db.execute(
            select(users.c.id).where(users.c.username_norm == username_norm)
        ).first()

        if username_exists:
            raise HTTPException(
                status_code=409,
                detail={
                    "ok": False,
                    "code": "unavailable",
                    "errors": [
                        error("username", "unavailable", "Choose a different username.")
                    ],
                },
            )

        password_hash = password_hasher.hash(password)
        verification_token = secrets.token_urlsafe(32)

        try:
            db.execute(
                insert(users).values(
                    email=email_norm,
                    email_norm=email_norm,
                    email_domain=email_domain,
                    username=username,
                    username_norm=username_norm,
                    display_name=display_name,
                    password_hash=password_hash,
                    email_verified=False,
                    verification_token_hash=verification_hash(verification_token),
                    created_at=now,
                )
            )
            db.commit()

            # Send verification_token by email out-of-band here.
            # Never return it in production logs or API responses.

        except IntegrityError:
            db.rollback()

            # Do not disclose existing email addresses.
            # Username conflicts are user-actionable; email conflicts get the same accepted response.
            username_exists_after_race = db.execute(
                select(users.c.id).where(users.c.username_norm == username_norm)
            ).first()

            if username_exists_after_race:
                raise HTTPException(
                    status_code=409,
                    detail={
                        "ok": False,
                        "code": "unavailable",
                        "errors": [
                            error("username", "unavailable", "Choose a different username.")
                        ],
                    },
                )

            await pad_response(start)
            return {
                "ok": True,
                "message": "If this registration can be completed, a verification email will be sent.",
            }

    await pad_response(start)
    return {
        "ok": True,
        "message": "If this registration can be completed, a verification email will be sent.",
    }
